<template>
  <div v-if="year">
    <v-menu max-width="100%" ref="menu1" v-model="dateMenu" :close-on-content-click="false" transition="scale-transition" offset-y>
      <template v-slot:activator="{ on, attrs }">
        <v-text-field v-model="displayDate" append-icon="$calendar" v-bind="attrs" dense outlined v-on="on" readonly width="200"></v-text-field>
      </template>
      <v-date-picker
        ref="datePiker"
        :max="allowMaxDate"
        :min="allowMinDate"
        :active-picker.sync="activePicker"
        :allowed-dates="allowedDates"
        v-model="date"
        no-title
        @click:year="saveYear"
        width="200"
      >
      </v-date-picker>
    </v-menu>
  </div>
  <div v-else-if="menu">
    <v-menu ref="menu1" v-model="dateMenu" :close-on-content-click="false" transition="scale-transition" offset-y>
      <template v-slot:activator="{ on, attrs }">
        <v-text-field
          v-model="displayDate"
          append-icon="$calendar"
          @click:append="appendClick"
          readonly
          v-on="on"
          v-bind="attrs"
          dense
          outlined
          slot-scope=""
          :clearable="clearable"
          color="white--text"
          @click:clear="onCleared"
        ></v-text-field>
      </template>
      <v-date-picker
        v-model="date"
        :max="allowMaxDate"
        :min="allowMinDate"
        :allowed-dates="allowedDates"
        dense
        outlined
        slot-scope=""
        scrollable
        no-title
        :disabled="disabled"
        @input="onSelectDate"
        :events="functionEvents"
        event-color="green lighten-1"
      >
      </v-date-picker>
    </v-menu>
  </div>
  <div v-else>
    <v-dialog ref="dialog" v-model="dateModal" :return-value.sync="date" width="290px">
      <template v-slot:activator="{ on, attrs }">
        <v-text-field
          v-model="displayDate"
          append-icon="$calendar"
          @click:append="appendClick"
          readonly
          v-on="on"
          v-bind="attrs"
          dense
          outlined
          slot-scope=""
          :clearable="clearable"
          color="white--text"
          @click:clear="onCleared"
        ></v-text-field>
      </template>
      <v-date-picker
        v-model="date"
        :max="allowMaxDate"
        :min="allowMinDate"
        :allowed-dates="allowedDates"
        dense
        outlined
        slot-scope=""
        scrollable
        no-title
        :disabled="disabled"
        @input="onSelectDate"
        :events="functionEvents"
        event-color="green lighten-1"
      >
      </v-date-picker>
    </v-dialog>

    <v-dialog ref="dialog2" v-model="timeModal" :return-value.sync="time" persistent>
      <v-time-picker v-if="timeModal" v-model="time" full-width :landscape="landscape" :events="arrayEvents" event-color="green lighten-1">
        <v-spacer></v-spacer>
        <v-btn text color="white--text" @click="timeModal = false">Cancel</v-btn>
        <v-btn text color="white--text" @click="set()">OK</v-btn>
      </v-time-picker>
    </v-dialog>
  </div>
</template>
