<script>
import { getCurrentDate, getYearFormat } from '@/utils/common.js'
export default {
  name: 'DateTimePicker',
  props: {
    //2023-05-22 by lyj events 속성추가
    functionEvents: {
      type: Function,
      default: () => {}
    },
    label: {
      type: String,
      default: () => {
        return undefined
      }
    },
    dateOnly: {
      //datePicker만 사용할지
      type: Boolean,
      default: false
    },
    allowMaxDate: {
      //datePicker의 선택가능한 최대날짜 설정
      type: String,
      default: () => {
        return ''
      }
    },
    allowMinDate: {
      //datePicker의 선택가능한 최소날짜 설정
      type: String,
      default: () => {
        return ''
      }
    },
    firstDisplayDate: {
      //text-field에 표시하는 초기 display날짜 설정
      type: [String, Function],
      default: () => {
        return ''
      }
    },
    disabled: {
      //비활성화
      type: Boolean,
      default: false
    },
    year: {
      type: Boolean,
      default: false
    },
    menu: {
      type: Boolean,
      default: false
    },
    allowedDates: {
      type: Function,
      default: null
    },
    clearable: {
      type: Boolean,
      default: false
    }
  },
  data: () => ({
    date: '',
    dateModal: false,
    time: '',
    timeModal: false,
    maxDate: '',
    minDate: '',
    displayDate: '',
    dateMenu: false,
    activePicker: null
  }),
  watch: {
    dateMenu(val) {
      val && setTimeout(() => (this.activePicker = 'YEAR'))
    },
    firstDisplayDate() {
      this.setFirstDisplayDate()
    }
  },
  mounted() {
    // this.setMaxDate()
    // this.setMinDate()
    this.setFirstDisplayDate()
  },
  methods: {
    appendClick() {
      this.dateModal = true
      this.dateMenu = true
    },
    set() {
      this.$emit('getDate', this.date)
      // this.date = this.date + ' ' + this.time
      this.displayDate = this.formatDate(this.date)
      if (this.menu) {
        this.$refs.menu1.save(this.date)
      } else {
        this.$refs.dialog.save(this.date)
        this.$refs.dialog2.save(this.time)
      }
    },
    // setMaxDate(){
    //   if(this.allowMaxDate != null) this.maxDate = this.allowMaxDate;
    //   else this.maxDate=''
    // },
    // setMinDate(){
    //   if(this.allowMinDate != null)  this.minDate = this.allowMinDate;
    //   else this.minDate=''
    // },
    setFirstDisplayDate() {
      if (this.firstDisplayDate != null && this.year) this.displayDate = getYearFormat(this.firstDisplayDate)
      else if (this.firstDisplayDate != null) this.displayDate = this.formatDate(this.firstDisplayDate)
      else this.displayDate = ''
    },
    formatDate(date) {
      if (!date) return null

      if (date.indexOf('-') > -1) {
        const [year, month, day] = date.split('-')
        return `${year}.${month}.${day}`
      }
      if (date.indexOf('.') > -1) {
        const [year, month, day] = date.split('.')
        return `${year}.${month}.${day}`
      }
    },
    onCleared() {
      this.date = null
      this.$emit('getDate', this.date)
      if (this.menu) {
        this.$refs.menu1.save(this.date)
      } else {
        this.$refs.dialog.save(this.date)
        this.$refs.dialog2.save(this.time)
      }
    },
    onSelectDate(e) {
      this.$emit('getDate', this.date)
      // this.date = this.date + ' ' + this.time
      this.displayDate = this.formatDate(this.date)
      if (this.menu) {
        this.$refs.menu1.save(this.date)
      } else {
        this.$refs.dialog.save(this.date)
        this.$refs.dialog2.save(this.time)
      }
    },

    saveYear(year) {
      this.date = `${year}-01`
      this.displayDate = year
      this.$refs.menu1.save(year)
      this.$emit('getDate', year)
    }
  }
}
</script>
